// ---------------------------------------------------------------------------
// bash-xlsx-diff-export — building a real .xlsx with zip and heredocs
// ---------------------------------------------------------------------------

describe('bash-xlsx-diff-export: writing .xlsx from shell', () => {
  it('writes a workbook that openpyxl — which shares no code with it — can read', () => {
    const out = fx.out('sh_changes.xlsx');
    const tsv = xldiffSh([fx.sample, '-f', 'tsv']);
    assert.equal(tsv.code, 0);

    const w = run('bash', [script('bash-xlsx-diff-export', 'write_xlsx.sh'), out], { input: tsv.stdout });
    assert.equal(w.code, 0, w.stderr);

    const shape = readXlsxShape(out);
    assert.deepEqual(shape.sheets, ['Changes']);
    assert.deepEqual(shape.tables, ['tbl_Changes'], 'registered as a real Excel Table');
    assert.equal(shape.freeze, 'A2');

    const [header, ...rows] = shape.rows;
    assert.deepEqual(header, ['Month', 'ID', 'Change_Status', 'Status', 'Owner']);
    assert.deepEqual(rows, GOLDEN_ROWS);
  });
});

// ---------------------------------------------------------------------------
// bash-xlsx-diff-verify — with the same negative control
// ---------------------------------------------------------------------------

describe('bash-xlsx-diff-verify: proving a diff file is honest, shell only', () => {
  const verify = (args) => run('bash', [script('bash-xlsx-diff-verify', 'verify.sh'), ...args]);

  it('PASSes an honest changes file', () => {
    const out = fx.out('sh_honest.xlsx');
    xldiff([fx.sample, '-o', out]);

    const r = verify([fx.sample, out]);
    assert.equal(r.code, 0, r.stdout + r.stderr);
    assert.match(r.stdout, /^PASS/m);
  });

  it('REJECTS the planted Removed-row bug and names the rule', () => {
    const honest = fx.out('sh_honest2.xlsx');
    xldiff([fx.sample, '-o', honest]);
    const bad = tamperCell(honest, fx.out('sh_tampered.xlsx'), {
      key: '102',
      status: 'Removed',
      col: 'Status',
      value: 'Active',
    });

    const r = verify([fx.sample, bad]);
    assert.equal(r.code, 1, 'a plausible-but-wrong file must not pass the shell verifier either');
    assert.match(
      r.stdout + r.stderr,
      /Mar\/102: Removed row carries Status='Active', but Feb \(the month it was last seen in\) says 'Inactive'/,
    );
  });
});

// ---------------------------------------------------------------------------
// bash-xlsx-month-diff — the end-to-end shell entry point
// ---------------------------------------------------------------------------

describe('bash-xlsx-month-diff: end-to-end with no Python at all', () => {
  it('inspect -> diff -> write -> verify, entirely in shell', () => {
    const out = fx.out('sh_e2e.xlsx');

    assert.equal(run('bash', [script('bash-xlsx-workbook-inspect', 'inspect.sh'), fx.sample]).code, 0);

    const tsv = xldiffSh([fx.sample, '-f', 'tsv']);
    assert.equal(tsv.code, 0);

    const w = run('bash', [script('bash-xlsx-diff-export', 'write_xlsx.sh'), out], { input: tsv.stdout });
    assert.equal(w.code, 0, w.stderr);

    const v = run('bash', [script('bash-xlsx-diff-verify', 'verify.sh'), fx.sample, out]);
    assert.equal(v.code, 0, v.stdout + v.stderr);

    const [, ...rows] = readXlsx(out);
    assert.deepEqual(rows, GOLDEN_ROWS);
  });
});

// ---------------------------------------------------------------------------
// Cross-implementation parity — the strongest check available
// ---------------------------------------------------------------------------

describe('parity: the bash suite and the Python suite agree', () => {
  for (const fixture of ['sample', 'sheets', 'gap', 'messy']) {
    for (const format of ['table', 'json']) {
      it(`${fixture}.xlsx as ${format}: byte-identical across both engines`, () => {
        const book = fx[fixture];
        const p = xldiff([book, '-f', format]);
        const s = xldiffSh([book, '-f', format]);
        assert.equal(p.code, 0, p.stderr);
        assert.equal(s.code, 0, s.stderr);
        assert.equal(s.stdout, p.stdout);

        // Exit codes are part of the contract too. PARITY.md compared stdout only, and an
        // exit-code divergence on the empty diff hid behind byte-identical output for
        // exactly that reason — a caller running `set -e` would have seen it before we did.
        assert.equal(s.code, p.code, 'the two engines must agree on the exit code, not just the bytes');
      });
    }
  }

  it('an .xlsx written by BASH passes the PYTHON verifier', () => {
    const out = fx.out('x_sh.xlsx');
    const tsv = xldiffSh([fx.sample, '-f', 'tsv']);
    run('bash', [script('bash-xlsx-diff-export', 'write_xlsx.sh'), out], { input: tsv.stdout });

    const r = run(PYTHON, [script('py-xlsx-diff-verify', 'verify_diff.py'), fx.sample, out]);
    assert.equal(r.code, 0, r.stdout + r.stderr);
  });

  it('an .xlsx written by PYTHON passes the BASH verifier', () => {
    const out = fx.out('x_py.xlsx');
    xldiff([fx.sample, '-o', out]);

    const r = run('bash', [script('bash-xlsx-diff-verify', 'verify.sh'), fx.sample, out]);
    assert.equal(r.code, 0, r.stdout + r.stderr);
  });
});
